use proptest::prelude::*;

proptest! {
    /// Property: no false negatives ever
    #[test]
    fn prop_no_false_negatives(
        workspaces in prop::collection::vec("/[a-z/]{5,30}", 1..100)
    ) {
        let paths: Vec<PathBuf> = workspaces.iter().map(PathBuf::from).collect();
        let cache = WorkspaceCache::new(paths.clone());

        for ws in &paths {
            prop_assert!(cache.contains(ws), "False negative: {:?}", ws);
        }
    }

    /// Property: disjoint paths return false
    #[test]
    fn prop_disjoint_paths_rejected(
        workspaces in prop::collection::vec("/workspace/[a-z]{3,10}", 1..50),
        others in prop::collection::vec("/other/[a-z]{3,10}", 1..50)
    ) {
        let paths: Vec<PathBuf> = workspaces.iter().map(PathBuf::from).collect();
        let cache = WorkspaceCache::new(paths);

        for other in &others {
            // This tests the full contains() path (bloom + exact)
            // May have false positives in bloom, but exact set rejects
            let path = PathBuf::from(other);
            // Verify through exact set (should always be false)
            prop_assert!(!cache.exact.contains(&path));
        }
    }
}
